var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"흥, 무르군. 그 정도 공격으로는 이 몸을 쓰러트릴 수 없다, 소녀여!","JPN":"ふん。甘いな、少女。その程度の攻撃では、この私を倒すことはできんぞ！","ENG":"You’re weak, girl. You can’t beat me with an attack like that!","TWN":"哼，退下吧！憑你三腳貓的功夫是打不倒我的，這位少女！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"웃기지 마! 난 아직 시작도 안 했다구!","JPN":"笑わせないでよ！　まだ始まってもないんだから！","ENG":"Don’t make me laugh! I haven’t even started yet!","TWN":"笑死！我根本還沒開始好嗎！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"좋아…! 간다!! 강렬~~!!","JPN":"よし……！　行くよ！！　強烈なーー！！","ENG":"Get ready, and go! Intense...","TWN":"很好…！去吧！猛烈的～～！！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"오새롬 킥!","JPN":"ケンドウ・アサネ流キック！","ENG":"Oh Saerom Kick!","TWN":"吳芷倫踢擊！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 악명 자자한 코핀 컴퍼니도 사무실 부수는 일은 드물다고 들었습니다만……","JPN":"あの悪名高いコフィンカンパニーでさえ、事務所を壊すことは滅多にないと聞きますが……","ENG":"Not even the notorious Coffin Company destroys its own office...","TWN":"我聽說連那個惡名昭彰的科芬公司也很少發生破壞辦公室的事……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이번 달만 벌써 세번째군요.","JPN":"今月でもう3回目ですね。","ENG":"This is the third time this month.","TWN":"這已經是這個月的第三次呢。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"그, 그치만 가브리엘 녀석이 먼저…!","JPN":"だ、だってガブリエルが先に……！","ENG":"But... Gabriel started it!","TWN":"都是…加布里埃爾那傢伙先…!"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"흥! 그대가 먼저 이 몸 가는 길목에 바나나 껍질을…!","JPN":"ふん！　君が先に私の行く手にバナナの皮を……！","ENG":"Hmph! You’re the one who dropped a banana peel in my way!","TWN":"拜託！是你先在我經過的路上扔香蕉皮…！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"아이 참! 그건 실수라니까!!","JPN":"だから！　わざとじゃないんだってば！！","ENG":"I told you, that was a mistake!","TWN":"吼唷！就說那是不小心的！！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…그만!!","JPN":"……静かに！！","ENG":"Stop!","TWN":"…都給我閉嘴！！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"제가 몇 번이나 부탁드렸을 겁니다.","JPN":"何度もお願いしたはずです。","ENG":"I’ve told you so many times.","TWN":"我已經跟你們說過多少次了。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"두 분의 싸움을 막지 못한다는 것은 알겠으니까… 하다못해 싸우려면 공용 훈련장을 이용하라고.","JPN":"お二人の喧嘩を止めるのは不可能なので、せめて公用の訓練場を利用してくださいと。","ENG":"I know I can’t stop you from fighting... If you have to fight, use the training ground.","TWN":"我知道我無法阻止你們不打架…但是要打，拜託你們到公用的訓練場去打嘛！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"몇 번이나… 몇 번이나… 그렇게 말했는데…!!","JPN":"何度も……何度も……お話ししたはずですよ……！！","ENG":"How many times... how many times did I tell you!","TWN":"我已經說過…很多…很多…很多次了！！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"야, 실장님 또 화났잖아. 네가 좀 진정시켜 봐. 파사의 심판자.","JPN":"ねえ、室長ってばまた怒っちゃったよ。あなたが何とかしてよね、破邪の審判者。","ENG":"Hey, Chief is mad again. Do something, the Judicator of Evil.","TWN":"都你啦！室長又生氣了！快想辦法讓室長消氣啊，破邪審判者！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"동료를 지키는 것도 정의의 사자가 할 일 아닌가. 가면 카운터 지망생.","JPN":"仲間を守ることも正義の味方の仕事ではないのか？　仮面カウンター志願者よ。","ENG":"You’re the hero of justice who should be protecting your teammates, the Masked Counter wannabe.","TWN":"守護同伴不是正義使者的該做的事嗎，蒙面制裁者鐵粉？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이럴 때만 둘 다 죽이 맞아선…!","JPN":"こういうときは、息がぴったりなんですから……！","ENG":"Now you’re on good terms now?","TWN":"只有在這種時候，你們才會在那邊一搭一唱的…！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"하아… 이젠 화내는 내가 더 바보 같아…….","JPN":"はあ……もう、怒ってるこっちが馬鹿馬鹿しい……","ENG":"*Sigh* I feel like an idiot...","TWN":"哀…搞得我現在像個笨蛋一樣……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니… 이제 두 사람을 용서해주세요.","JPN":"ホノカさん、もう二人を許してください。","ENG":"Jin... please forgive them.","TWN":"李珍姐…請你原諒他們。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};